-- ── Consensus (world-wide game parameters) ────────────────────────────────────
INSERT OR IGNORE INTO consensus (key, value, value_type, name, purpose) VALUES
  ('CAT.COOLDOWN_HOUR_BETWEEN_CARE',  '1',  'NUMBER', 'Care cooldown',     'Minimum cooldown time (in hours) between caring for your cat'),
  ('CAT.GROWTH_PER_CARE',     '1',  'NUMBER', 'Growth stat gained per care', 'Growth stat gained when caring for your cat'),
  ('CAT.EMOTION_PER_CARE',    '5',  'NUMBER', 'Emotion stat gained per care', 'Emotion stat gained when caring for your cat'),
  ('CAT.EMOTION_DECREASE',    '10', 'NUMBER', 'Emotion decrease per cycle', 'Emotion stat lost per cycle when you do not care for your cat'),
  ('CAT.EMOTION_DECREASE_FREQUENCY_HOUR', '12', 'NUMBER', 'Emotion decrease frequency (hours)', 'How often (in hours) emotion decreases if cat was not cared for'),
  ('CAT.MAX_GROWTH',          '100', 'NUMBER', 'Maximum growth stat', 'Maximum growth stat your cat can have')
;

-- ── Big5 Personality Traits ────────────────────────────────────
INSERT OR IGNORE INTO personality_question (id, text, keyed, domain, description_level_1, description_level_2, description_level_3, description_level_4, description_level_5) VALUES
  ('019e3e79-1504-7aa9-be83-de4f901b42f1', 'Worry about things', 'plus', 'neuroticism', 'Worry? You sleep like a rock. Zero issues.', 'You worry a little but forget about it pretty fast.', 'You worry sometimes but know how to calm down.', 'Small things easily turn into big worries in your head.', 'You worry about everything, including worrying too much.'),
  ('019e3e79-1504-7aa9-be83-e54b410d822d', 'Make friends easily', 'plus', 'extraversion', 'You and your cat have a very tight circle.', 'Making friends takes some time to warm up.', 'You make friends okay, nothing dramatic.', 'People tend to like you. Friendships happen naturally.', 'You show up somewhere and leave with a bunch of new friends.'),
  ('019e3e79-1504-7aa9-be83-e89e502123d5', 'Have a vivid imagination', 'plus', 'openness', 'Daydreaming? Reality is more than enough for you.', 'Your imagination stays pretty quiet.', 'You get creative sparks once in a while.', 'You have a lively imagination.', 'You can turn a boring errand into a whole movie in your head.'),
  ('019e3e79-1504-7aa9-be83-f1282de034bb', 'Trust others', 'plus', 'agreeableness', 'Trust is earned. Slowly. With receipts.', 'You trust people, but only after some time.', 'You give people a chance but keep your guard up a little.', 'You generally trust others and see the good in them.', 'You trust people pretty fast — sometimes too fast.'),
  ('019e3e79-1504-7aa9-be83-fd1d4353d647', 'Complete tasks successfully', 'plus', 'conscientiousness', 'Great at starting, not so great at finishing.', 'You finish things when the mood hits.', 'You usually get stuff done, more or less.', 'You’re solid at completing what you start.', 'You finish tasks properly and often ahead of time.'),
  ('019e3e79-1504-7aa9-be84-01b620636a3f', 'Get angry easily', 'plus', 'neuroticism', 'You’re basically zen. Almost nothing bothers you.', 'It takes a lot to get you angry.', 'You get irritated sometimes but cool off fast.', 'You can get angry pretty quickly.', 'Your patience runs out faster than you’d like.'),
  ('019e3e79-1504-7aa9-be84-0ec95109415b', 'Love large parties', 'plus', 'extraversion', 'Big parties? Hard pass. Home is better.', 'Large crowds can feel overwhelming.', 'You enjoy big parties sometimes but get tired afterward.', 'You like the energy of big parties.', 'You’re usually one of the last ones standing at parties.'),
  ('019e3e79-1504-7aa9-be84-16f50571ebf8', 'Believe in the importance of art', 'plus', 'openness', 'Art is fine, but not essential for you.', 'Art isn’t a huge part of your life.', 'You see the value in art.', 'Art matters to you. Life is better with it.', 'You believe art can really move and change people.'),
  ('019e3e79-1504-7aa9-be84-1b92dd755546', 'Use others for my own ends', 'minus', 'agreeableness', 'You’d never use people for your own benefit.', 'You almost never use others.', 'You might do it rarely but feel guilty.', 'You sometimes use people to get ahead.', 'You’re pretty strategic when you want something.'),
  ('019e3e79-1504-7aa9-be84-25ec6efb61f6', 'Like to tidy up', 'plus', 'conscientiousness', 'Mess? What mess? You barely notice it.', 'You clean when it starts getting bad.', 'You keep things decently tidy.', 'You like a clean space and feel better when it is.', 'You’re always organizing and straightening things up.'),
  ('019e3e79-1504-7aa9-be84-2a6fa2c150d9', 'Often feel blue', 'plus', 'neuroticism', 'You stay pretty positive most of the time.', 'You feel down occasionally but recover fast.', 'You have normal good and bad days.', 'You feel sad or low quite often.', 'Negative moods hit you hard and stick around.'),
  ('019e3e79-1504-7aa9-be84-330a44aa7db3', 'Take charge', 'plus', 'extraversion', 'You’d rather follow than lead.', 'You take charge only when someone has to.', 'You can lead if needed.', 'You like being in charge.', 'You naturally end up leading most of the time.'),
  ('019e3e79-1504-7aa9-be84-3de9773ef6e4', 'Experience my emotions intensely', 'plus', 'openness', 'Your emotions are usually mild and steady.', 'You feel things but not too deeply.', 'You experience emotions clearly but keep them balanced.', 'Your emotions run pretty strong.', 'Emotions hit you like a truck.'),
  ('019e3e79-1504-7aa9-be84-4547b7a99a8c', 'Love to help others', 'plus', 'agreeableness', 'Helping others isn’t really your priority.', 'You help when it’s easy or asked.', 'You enjoy helping when you can.', 'You genuinely like helping people.', 'You’re usually the first to jump in and help.'),
  ('019e3e79-1504-7aa9-be84-4c15d2a9cf00', 'Keep my promises', 'plus', 'conscientiousness', 'Promises are more like suggestions.', 'You try but sometimes forget.', 'You usually keep your word.', 'Your word actually means something.', 'If you promised it, consider it done.'),
  ('019e3e79-1504-7aa9-be84-557676f7e99b', 'Find it difficult to approach others', 'plus', 'neuroticism', 'Approaching people feels easy and natural.', 'You get a bit nervous but still do it.', 'It depends on the situation.', 'Approaching others takes real effort.', 'Starting a conversation feels like climbing a mountain.'),
  ('019e3e79-1504-7aa9-be84-5d3151334737', 'Am always busy', 'plus', 'extraversion', 'You protect your free time like treasure.', 'You prefer a relaxed pace.', 'You stay busy but still rest.', 'You’re usually doing something.', 'Your schedule is always full and you love it.'),
  ('019e3e79-1504-7aa9-be84-64be32b31261', 'Prefer variety to routine', 'plus', 'openness', 'You love your routines and hate change.', 'You prefer familiar things.', 'You like some variety but routine is nice too.', 'You enjoy mixing things up.', 'Routine bores you to death. You need constant change.'),
  ('019e3e79-1504-7aa9-be84-68d1a97cd93f', 'Love a good fight', 'minus', 'agreeableness', 'You avoid conflict like the plague.', 'Arguments are not your thing.', 'You’ll argue if you have to.', 'You don’t mind a good debate.', 'You actually enjoy a solid argument.'),
  ('019e3e79-1504-7aa9-be84-77c7d44b77b5', 'Work hard', 'plus', 'conscientiousness', 'You work at a very chill pace.', 'You work hard when you feel like it.', 'You put in good effort when it matters.', 'You’re a solid hard worker.', 'You consistently outwork most people.'),
  ('019e3e79-1504-7aa9-be84-7e41a1b1ebc3', 'Go on binges', 'plus', 'neuroticism', 'You almost never lose control.', 'You rarely go overboard.', 'You sometimes binge when stressed.', 'You have fairly frequent binges.', 'You often completely lose control.'),
  ('019e3e79-1504-7aa9-be84-8477a15a0339', 'Love excitement', 'plus', 'extraversion', 'You prefer things calm and quiet.', 'You like mild excitement.', 'You enjoy excitement in moderation.', 'You actively seek fun and thrills.', 'You crave excitement all the time.'),
  ('019e3e79-1504-7aa9-be84-8a7413b256a9', 'Love to read challenging material', 'plus', 'openness', 'You prefer easy, light reading.', 'You read challenging stuff sometimes.', 'You enjoy deeper topics occasionally.', 'You like intellectually challenging material.', 'You love difficult and abstract reading.'),
  ('019e3e79-1504-7aa9-be84-92a4a8b1378e', 'Believe that I am better than others', 'minus', 'agreeableness', 'You see yourself as equal to everyone.', 'You rarely feel superior.', 'You sometimes feel a bit better.', 'You often think you’re better than most.', 'You strongly believe you’re superior.'),
  ('019e3e79-1504-7aa9-be84-9d0fed51eb38', 'Am always prepared', 'plus', 'conscientiousness', 'You usually wing it.', 'You prepare when it matters.', 'You’re reasonably prepared.', 'You like being well prepared.', 'You’re always ready for anything.'),
  ('019e3e79-1504-7aa9-be84-a193ed13cb1b', 'Panic easily', 'plus', 'neuroticism', 'You stay calm even in chaos.', 'You rarely panic.', 'You panic under strong pressure.', 'You tend to panic quite easily.', 'You panic at the smallest things.'),
  ('019e3e79-1504-7aa9-be84-ab8358cebfa3', 'Radiate joy', 'plus', 'extraversion', 'You’re usually more serious.', 'You show joy when you feel it.', 'You have a generally positive vibe.', 'You bring good energy to places.', 'You light up the room wherever you go.'),
  ('019e3e79-1504-7aa9-be84-b7c0d90c3b6f', 'Tend to vote for liberal political candidates', 'plus', 'openness', 'You strongly prefer conservative candidates.', 'You usually lean conservative.', 'Your views are pretty balanced.', 'You often support liberal candidates.', 'You strongly lean liberal.'),
  ('019e3e79-1504-7aa9-be84-bd1bce23e69a', 'Sympathize with the homeless', 'plus', 'agreeableness', 'You don’t feel much sympathy.', 'You feel some sympathy.', 'You feel sympathy when you see them.', 'You genuinely sympathize.', 'You feel deep compassion for them.'),
  ('019e3e79-1504-7aa9-be84-c5a32e575325', 'Jump into things without thinking', 'minus', 'conscientiousness', 'You always think things through first.', 'You rarely act impulsively.', 'You sometimes jump in without thinking.', 'You often act first, think later.', 'You regularly jump into things headfirst.'),
  ('019e3e79-1504-7aa9-be84-ceefe4010fe6', 'Fear for the worst', 'plus', 'neuroticism', 'You stay pretty optimistic.', 'You sometimes expect the worst.', 'You occasionally fear bad outcomes.', 'You often expect things to go wrong.', 'You almost always prepare for the worst.'),
  ('019e3e79-1504-7aa9-be84-d5b49bde92f6', 'Feel comfortable around people', 'plus', 'extraversion', 'You often feel awkward around people.', 'You’re comfortable mostly with close friends.', 'You feel okay in small groups.', 'You feel comfortable around most people.', 'You feel at ease with almost anyone.'),
  ('019e3e79-1504-7aa9-be84-df0e93c83ed2', 'Enjoy wild flights of fantasy', 'plus', 'openness', 'You prefer practical thinking.', 'You enjoy fantasy occasionally.', 'You sometimes let your mind wander wildly.', 'You often enjoy wild fantasies.', 'Your imagination runs completely wild.'),
  ('019e3e79-1504-7aa9-be84-e2f9b0f1b62f', 'Believe that others have good intentions', 'plus', 'agreeableness', 'You assume people have hidden motives.', 'You’re cautious about intentions.', 'You usually give the benefit of the doubt.', 'You believe most people mean well.', 'You almost always assume good intentions.'),
  ('019e3e79-1504-7aa9-be84-ec9eb673c704', 'Excel in what I do', 'plus', 'conscientiousness', 'You don’t focus much on excelling.', 'You do what’s needed.', 'You usually do good work.', 'You strive to excel.', 'You always aim for excellence.'),
  ('019e3e79-1504-7aa9-be84-f1c6a90361c7', 'Get irritated easily', 'plus', 'neuroticism', 'It takes a lot to irritate you.', 'You get irritated occasionally.', 'You get irritated more than average.', 'You can get irritated quite easily.', 'Almost everything irritates you.'),
  ('019e3e79-1504-7aa9-be84-fa81be886025', 'Talk to a lot of different people at parties', 'plus', 'extraversion', 'You stick to one or two people.', 'You talk to a few people.', 'You chat with several people.', 'You enjoy talking to many different people.', 'You talk to almost everyone at the party.'),
  ('019e3e79-1504-7aa9-be85-03e512054e1c', 'See beauty in things that others might not notice', 'plus', 'openness', 'You focus on practical things.', 'You notice beauty occasionally.', 'You sometimes see what others miss.', 'You often notice subtle beauty.', 'You see beauty everywhere.'),
  ('019e3e79-1504-7aa9-be85-09f6c368d96b', 'Cheat to get ahead', 'minus', 'agreeableness', 'You would never cheat.', 'You rarely consider it.', 'You might bend rules slightly.', 'You sometimes cheat if it helps.', 'You’re willing to cheat to get ahead.'),
  ('019e3e79-1504-7aa9-be85-179a657a6fba', 'Often forget to put things back in their proper place', 'minus', 'conscientiousness', 'You always put things back.', 'You usually remember.', 'You forget sometimes.', 'You often leave things out.', 'Your stuff is usually everywhere.'),
  ('019e3e79-1504-7aa9-be85-1d6f3e2820e1', 'Dislike myself', 'plus', 'neuroticism', 'You have a healthy self-image.', 'You have occasional self-doubt.', 'You sometimes dislike parts of yourself.', 'You often feel bad about yourself.', 'You strongly dislike yourself.'),
  ('019e3e79-1504-7aa9-be85-23af222eba91', 'Try to lead others', 'plus', 'extraversion', 'You prefer not to lead.', 'You lead when needed.', 'You sometimes take the lead.', 'You often try to lead.', 'You naturally take charge.'),
  ('019e3e79-1504-7aa9-be85-2e578b259fde', 'Feel others'' emotions', 'plus', 'openness', 'You rarely notice others’ feelings.', 'You sometimes pick up on emotions.', 'You can usually sense how others feel.', 'You’re quite empathetic.', 'You deeply feel what others feel.'),
  ('019e3e79-1504-7aa9-be85-36575eeeb76b', 'Am concerned about others', 'plus', 'agreeableness', 'You focus mostly on yourself.', 'You care when it’s convenient.', 'You show concern for others.', 'You genuinely care about others.', 'You’re deeply concerned about other people.'),
  ('019e3e79-1504-7aa9-be85-3e00d8b65a71', 'Tell the truth', 'plus', 'conscientiousness', 'You sometimes stretch the truth.', 'You tell the truth most times.', 'You usually try to be honest.', 'You value honesty a lot.', 'You always tell the truth.'),
  ('019e3e79-1504-7aa9-be85-43e63378887f', 'Am afraid to draw attention to myself', 'plus', 'neuroticism', 'You enjoy being the center of attention.', 'You don’t mind attention.', 'You feel a bit uncomfortable with attention.', 'You prefer to stay low-key.', 'You hate drawing any attention to yourself.'),
  ('019e3e79-1504-7aa9-be85-49ddf3ad6e31', 'Am always on the go', 'plus', 'extraversion', 'You prefer a slow, relaxed life.', 'You stay moderately active.', 'You keep busy most days.', 'You’re almost always doing something.', 'You’re constantly on the move.'),
  ('019e3e79-1504-7aa9-be85-501f6439cbad', 'Prefer to stick with things that I know', 'minus', 'openness', 'You love trying new things.', 'You’re open to new experiences.', 'You like some variety.', 'You prefer sticking to what you know.', 'You strongly dislike change.'),
  ('019e3e79-1504-7aa9-be85-59eef54b782d', 'Yell at people', 'minus', 'agreeableness', 'You almost never raise your voice.', 'You rarely yell.', 'You yell only when really angry.', 'You sometimes yell at people.', 'You yell quite often.'),
  ('019e3e79-1504-7aa9-be85-601fa6d459f1', 'Do more than what''s expected of me', 'plus', 'conscientiousness', 'You do the bare minimum.', 'You do what’s expected.', 'You sometimes go above and beyond.', 'You often do more than required.', 'You always exceed expectations.'),
  ('019e3e79-1504-7aa9-be85-6a4b00ac13d1', 'Rarely overindulge', 'minus', 'neuroticism', 'You frequently overindulge.', 'You sometimes overdo it.', 'You overindulge occasionally.', 'You rarely overindulge.', 'You almost never overindulge.'),
  ('019e3e79-1504-7aa9-be85-763ab3b75aa6', 'Seek adventure', 'plus', 'extraversion', 'You prefer safety over adventure.', 'You seek mild adventure.', 'You enjoy some adventure.', 'You actively look for adventure.', 'You live for adventure and thrills.'),
  ('019e3e79-1504-7aa9-be85-7e7277eb292e', 'Avoid philosophical discussions', 'minus', 'openness', 'You love deep philosophical talks.', 'You sometimes enjoy them.', 'You’re neutral about them.', 'You usually avoid them.', 'You have zero interest in philosophical discussions.'),
  ('019e3e79-1504-7aa9-be85-80a2bdb1168d', 'Think highly of myself', 'minus', 'agreeableness', 'You are very humble.', 'You have a balanced self-view.', 'You sometimes think highly of yourself.', 'You often have a high opinion of yourself.', 'You think very highly of yourself.'),
  ('019e3e79-1504-7aa9-be85-8e62d1cae63e', 'Carry out my plans', 'plus', 'conscientiousness', 'Your plans often stay as plans.', 'You carry out plans sometimes.', 'You usually follow through.', 'You reliably carry out your plans.', 'You always execute your plans successfully.'),
  ('019e3e79-1504-7aa9-be85-90224e636e6e', 'Become overwhelmed by events', 'plus', 'neuroticism', 'You handle events with ease.', 'You rarely feel overwhelmed.', 'You sometimes get overwhelmed.', 'You often feel overwhelmed.', 'You easily get overwhelmed by life.'),
  ('019e3e79-1504-7aa9-be85-9b7d8a9d6a1c', 'Have a lot of fun', 'plus', 'extraversion', 'You tend to be quite serious.', 'You have fun in moderation.', 'You enjoy fun when it comes.', 'You have a lot of fun.', 'You live for fun and good times.'),
  ('019e3e79-1504-7aa9-be85-a5c9c2d93670', 'Believe that there is no absolute right and wrong', 'plus', 'openness', 'You believe in clear right and wrong.', 'You mostly see clear morals.', 'You think morality is somewhat relative.', 'You see right and wrong as mostly relative.', 'You strongly believe there’s no absolute right or wrong.'),
  ('019e3e79-1504-7aa9-be85-ab1cbb6fadd9', 'Feel sympathy for those who are worse off than myself', 'plus', 'agreeableness', 'You feel little sympathy.', 'You feel sympathy sometimes.', 'You often feel sympathy.', 'You feel strong sympathy.', 'You have deep compassion for those worse off.'),
  ('019e3e79-1504-7aa9-be85-b0738b541a92', 'Make rash decisions', 'minus', 'conscientiousness', 'You always think carefully.', 'You rarely make rash decisions.', 'You sometimes act impulsively.', 'You often make rash decisions.', 'You almost always act without thinking.'),
  ('019e3e79-1504-7aa9-be85-b849414cba94', 'Am afraid of many things', 'plus', 'neuroticism', 'You’re afraid of very few things.', 'You have a few fears.', 'You have some fears.', 'You’re afraid of quite a lot.', 'You’re afraid of many things.'),
  ('019e3e79-1504-7aa9-be85-c1306767e7c0', 'Avoid contacts with others', 'minus', 'extraversion', 'You actively seek contact with others.', 'You enjoy social contact.', 'You are selective.', 'You often avoid contact.', 'You strongly prefer to be alone.'),
  ('019e3e79-1504-7aa9-be85-cf4deb393260', 'Love to daydream', 'plus', 'openness', 'You almost never daydream.', 'You daydream occasionally.', 'You daydream sometimes.', 'You daydream a lot.', 'Your head is constantly in the clouds.'),
  ('019e3e79-1504-7aa9-be85-d5308f0e1d99', 'Trust what people say', 'plus', 'agreeableness', 'You are very skeptical.', 'You trust selectively.', 'You usually trust people.', 'You generally believe what people say.', 'You trust almost everything people tell you.'),
  ('019e3e79-1504-7aa9-be85-da1ae338e003', 'Handle tasks smoothly', 'plus', 'conscientiousness', 'You often struggle with tasks.', 'You handle tasks okay.', 'You usually handle tasks well.', 'You handle tasks smoothly.', 'You make tasks look effortless.'),
  ('019e3e79-1504-7aa9-be85-e0c3bc6d8bf6', 'Lose my temper', 'plus', 'neuroticism', 'You almost never lose your temper.', 'You rarely lose it.', 'You lose your temper occasionally.', 'You lose your temper fairly often.', 'You lose your temper very easily.'),
  ('019e3e79-1504-7aa9-be85-ee4a87ee2620', 'Prefer to be alone', 'minus', 'extraversion', 'You almost always want company.', 'You like a mix.', 'You enjoy alone time sometimes.', 'You often prefer to be alone.', 'You strongly prefer solitude.'),
  ('019e3e79-1504-7aa9-be85-f0e030d9ca66', 'Do not like poetry', 'minus', 'openness', 'You really love poetry.', 'You sometimes enjoy poetry.', 'You’re neutral about poetry.', 'You don’t like poetry much.', 'You strongly dislike poetry.'),
  ('019e3e79-1504-7aa9-be85-ff9d49378c13', 'Take advantage of others', 'minus', 'agreeableness', 'You never take advantage.', 'You rarely do.', 'You might occasionally.', 'You sometimes take advantage.', 'You often take advantage of others.'),
  ('019e3e79-1504-7aa9-be86-020d3e107613', 'Leave a mess in my room', 'minus', 'conscientiousness', 'Your room is always spotless.', 'You keep it fairly tidy.', 'It gets messy sometimes.', 'You often leave a mess.', 'Your room is usually a disaster zone.'),
  ('019e3e79-1504-7aa9-be86-0c15aa2c5434', 'Am often down in the dumps', 'plus', 'neuroticism', 'You are rarely down.', 'You feel down occasionally.', 'You have periods of feeling low.', 'You often feel down.', 'You frequently feel down in the dumps.'),
  ('019e3e79-1504-7aa9-be86-16e03a6810b8', 'Take control of things', 'plus', 'extraversion', 'You prefer others to lead.', 'You take control when necessary.', 'You sometimes take control.', 'You like taking control.', 'You naturally take control everywhere.'),
  ('019e3e79-1504-7aa9-be86-1e8bd5d237e8', 'Rarely notice my emotional reactions', 'minus', 'openness', 'You are very aware of your emotions.', 'You usually notice how you feel.', 'You sometimes miss your feelings.', 'You rarely notice your emotions.', 'You are often unaware of your own feelings.'),
  ('019e3e79-1504-7aa9-be86-20edab2426e9', 'Am indifferent to the feelings of others', 'minus', 'agreeableness', 'You are very sensitive to others.', 'You usually care.', 'You sometimes feel indifferent.', 'You are often indifferent.', 'You are generally indifferent to others’ feelings.'),
  ('019e3e79-1504-7aa9-be86-2b26613dbaf6', 'Break rules', 'minus', 'conscientiousness', 'You always follow rules.', 'You rarely break rules.', 'You break small rules sometimes.', 'You often break rules.', 'You frequently break rules.'),
  ('019e3e79-1504-7aa9-be86-342301efec00', 'Only feel comfortable with friends', 'plus', 'neuroticism', 'You feel comfortable with almost anyone.', 'You’re okay with acquaintances.', 'You’re most comfortable with friends.', 'You only feel comfortable with close friends.', 'You feel anxious around non-friends.'),
  ('019e3e79-1504-7aa9-be86-3e55c9fc4084', 'Do a lot in my spare time', 'plus', 'extraversion', 'You prefer relaxing and doing little.', 'You do some activities.', 'You stay moderately active.', 'You do quite a lot in your free time.', 'You’re always active even in spare time.'),
  ('019e3e79-1504-7aa9-be86-421c047ecaf5', 'Dislike changes', 'minus', 'openness', 'You love change and new things.', 'You’re open to change.', 'You like some stability.', 'You generally dislike changes.', 'You hate any kind of change.'),
  ('019e3e79-1504-7aa9-be86-4860c888630d', 'Insult people', 'minus', 'agreeableness', 'You never insult others.', 'You rarely insult people.', 'You insult only when provoked.', 'You sometimes insult people.', 'You frequently insult others.'),
  ('019e3e79-1504-7aa9-be86-5392c4bf68ac', 'Do just enough work to get by', 'minus', 'conscientiousness', 'You always go the extra mile.', 'You usually do more than needed.', 'You do what’s required.', 'You often do the minimum.', 'You do just enough to get by.'),
  ('019e3e79-1504-7aa9-be86-5b24a6529abd', 'Easily resist temptations', 'minus', 'neuroticism', 'You struggle with temptations.', 'You sometimes give in.', 'You can usually resist.', 'You resist temptations well.', 'You easily resist almost everything.'),
  ('019e3e79-1504-7aa9-be86-66b4ee790de1', 'Enjoy being reckless', 'plus', 'extraversion', 'You are very careful.', 'You are occasionally reckless.', 'You enjoy some risk.', 'You like being reckless sometimes.', 'You love being wild and reckless.'),
  ('019e3e79-1504-7aa9-be86-6ad6a7aecf58', 'Have difficulty understanding abstract ideas', 'minus', 'openness', 'You easily understand abstract ideas.', 'You understand most of them.', 'You sometimes struggle.', 'You often have difficulty.', 'Abstract ideas are very hard for you.'),
  ('019e3e79-1504-7aa9-be86-77cdb9de42a5', 'Have a high opinion of myself', 'minus', 'agreeableness', 'You are very humble.', 'You have a modest view.', 'You have a positive self-image.', 'You think quite highly of yourself.', 'You have an extremely high opinion of yourself.'),
  ('019e3e79-1504-7aa9-be86-7bfa60401f7b', 'Waste my time', 'minus', 'conscientiousness', 'You use time very efficiently.', 'You rarely waste time.', 'You waste some time.', 'You often waste time.', 'You waste a lot of time.'),
  ('019e3e79-1504-7aa9-be86-800e70df8076', 'Feel that I''m unable to deal with things', 'plus', 'neuroticism', 'You feel confident handling most things.', 'You sometimes doubt yourself.', 'You occasionally feel unable.', 'You often feel unable to cope.', 'You frequently feel completely unable to deal with life.'),
  ('019e3e79-1504-7aa9-be86-8c23dc12445c', 'Love life', 'plus', 'extraversion', 'You often feel dissatisfied.', 'You have average enjoyment.', 'You generally like life.', 'You really enjoy life.', 'You absolutely love life.'),
  ('019e3e79-1504-7aa9-be86-95dcd8040a13', 'Tend to vote for conservative political candidates', 'minus', 'openness', 'You strongly prefer liberal candidates.', 'You lean liberal.', 'Your views are mixed.', 'You usually vote conservative.', 'You strongly prefer conservative candidates.'),
  ('019e3e79-1504-7aa9-be86-9b30d262f91e', 'Am not interested in other people''s problems', 'minus', 'agreeableness', 'You are very interested in others’ problems.', 'You sometimes care.', 'You are moderately interested.', 'You are often not interested.', 'You don’t care about other people’s problems.'),
  ('019e3e79-1504-7aa9-be86-a7b73a871cc9', 'Rush into things', 'minus', 'conscientiousness', 'You never rush.', 'You rarely rush.', 'You sometimes rush.', 'You often rush into things.', 'You almost always rush.'),
